// Apriori+ABC sonucu + Gemini açıklamasını birleştir
const abc = $('2. ABC Rota Optimizasyonu').item.json;
const gem = $('3. Gemini AI Açıklama').item.json;

let aiExplanation = '';
try {
  aiExplanation = gem.candidates[0].content.parts[0].text;
} catch(e) {
  aiExplanation = 'Açıklama üretilemedi.';
}

return [{
  json: {
    wave_id:          abc.wave_id,
    optimal_route:    abc.optimal_route,
    total_distance:   abc.total_distance,
    greedy_distance:  abc.greedy_distance,
    improvement_pct:  abc.improvement,
    n_products:       abc.n_products,
    algorithm:        abc.algorithm,
    apriori_used:     abc.apriori_used,
    rf_prediction:    abc.rf_prediction,
    anomaly:          abc.anomaly,
    anomaly_message:  abc.anomaly_message,
    ai_explanation:   aiExplanation,
    timestamp:        new Date().toISOString(),
  }
}];

